mapper.select:
select a.id, a.name, a.introduction, a.district_id, a.district_name, a.city_id, a.city_name, a.province_id, a.province_name, a.address_detail, a.latitude, a.longitude, a.phone, a.is_release, ifnull(b.cnt, 0) as total_room_count, ifnull(b.cnt, 0) - ifnull(c.cnt, 0) as free_room_count from (select id, name, introduction, district_id, district_name, city_id, city_name, province_id, province_name, address_detail, latitude, longitude, phone, is_release from apartment_info
is_deleted = 0
and province_id = #{queryVo.provinceId}
and city_id = #{queryVo.cityId}
and district_id = #{queryVo.districtId}
) a left join (select apartment_id, count(*) cnt from room_info where is_deleted = 0 and is_release = 1 group by apartment_id ) b on a.id = b.apartment_id left join (select
apartment_id, count(*) cnt from lease_agreement where is_deleted = 0 and status in (2, 5) group by apartment_id ) c on a.id = c.apartment_id
